async function main() {
    console.log('Seeding SchoolYear...');
    await prisma.schoolYear.upsert({
        where: { year: '2024-2025' },
        update: { is_active: true },
        create: { year: '2024-2025', is_active: true }
    });

    console.log('Seeding Sections...');
    const sectionMap = new Map();
    for (const sec of sectionsData) {
        const created = await prisma.section.upsert({
            where: { name_academic_year: { name: sec.name, academic_year: sec.academic_year } },
            update: { grade_level: sec.grade_level },
            create: { name: sec.name, grade_level: sec.grade_level, academic_year: sec.academic_year }
        });
        sectionMap.set(sec.name, created.id);
    }

    console.log('Seeding Students...');
    const defaultPasswordHash = await hash('student123', { memoryCost: 19456, timeCost: 2, outputLen: 32, parallelism: 1 });

    for (let i = 0; i < studentsData.length; i++) {
        const s = studentsData[i];
        const sectionId = sectionMap.get(s.grade);
        
        let user = await prisma.user.findUnique({ where: { email: s.email } });
        if (!user) {
            const userId = generateIdFromEntropySize(10);
            user = await prisma.user.create({
                data: {
                    id: userId,
                    email: s.email,
                    full_name: s.full_name,
                    password: defaultPasswordHash,
                    role: 'student',
                    user_roles: {
                        create: { role: 'student' }
                    },
                    student_profile: {
                        create: {
                            student_number: s.student_number,
                            section_id: sectionId,
                            status: 'active',
                            birthdate: s.birthdate ? new Date(s.birthdate) : null,
                            age: s.age,
                            gender: s.gender,
                            mother_contact: s.mother_contact,
                            mother_name: s.mother_name,
                            father_contact: s.father_contact,
                            father_name: s.father_name,
                            philippine_address: s.philippine_address,
                            uae_address: s.uae_address
                        }
                    }
                }
            });
        }
        if (i % 50 === 0) console.log(`Processed ${i} students...`);
    }
    console.log('Seeding complete!');
}

main().catch(e => console.error(e)).finally(() => prisma.$disconnect());
